#!/usr/bin/env python
# encoding: utf-8

'''
Класс для работы с xml-файлами с сайта www.openexoplanetcatalogue.com
Позволяет считать данные и немного преобразовать некоторые 
отдельные параметры для дальнейшей работы.
'''

import sys
from lxml import etree
import numpy as np

class ExoplanetCatalogue( dict ):
 def __init__(self, xmlFileName ):
  dict.__init__(self)
  self["xmlFileName"] = xmlFileName
  tree = etree.parse( self["xmlFileName"] )
  self.parseSystemSection( tree.getroot() )
  self.correctValues()

 def correctValues(self):
  for keyw, new_keyw in [ 
                          ("planet.transittime", "transittime" ),
                          ("planet.period", "period"),
                          ("star.magV", "mag"),
                          ("planet.name", "name"),
                        ]:
   if keyw in self:
    print( "copy  {} --> {} ".format(keyw, new_keyw) )
    self[new_keyw] = self[keyw]


  for keyw, new_keyw in [ 
                          ("system.rightascension","RA"), 
                          ("system.declination","DEC"), 
                        ]:
   if keyw  in self:
    self[new_keyw] = self[keyw].replace(" ",":")

  for new_keyw in [ 
                          "duraction", 
                          "trans_depht",
                        ]:
    self[new_keyw] = 0

  if not "planet.istransiting"  in self:
   self["transittime"] = np.nan
   self["period"] = np.nan
   self["mag"] = np.nan

 def parseSystemSection(self, subtree):
  for item in subtree:
   if not len(item):
    tag, value = "system.{}".format(item.tag), item.text
    if not tag in self:
     self[ tag ] = value
   else:
    if item.tag=="star": 
     self.parseStarSection(item)

 def parseStarSection(self, subtree):
  for item in subtree:
   if not len(item):
    tag, value = "star.{}".format(item.tag), item.text
    if not tag in self:
     self[ tag ] = value
   else:
    if item.tag=="planet": 
     self.parsePlanetSection(item)

 def parsePlanetSection(self, subtree):
  for item in subtree:
   if not len(item):
    tag, value = "planet.{}".format(item.tag), item.text
    if not tag in self:
     self[ tag ] = value

if __name__ == '__main__' :
 obj = ExoplanetCatalogue("WASP-107.xml")
 print( obj )

